module RefModule (
    input [7:0] data_in,
    output reg [7:0] checksum_out
);
    integer i;
    reg [7:0] unused_sum;

    always @(*) begin
        unused_sum = 8'b0;
        for (i = 0; i < 8; i = i + 1) begin
            unused_sum = unused_sum + data_in[i];
        end
        checksum_out = unused_sum % 256;
    end
endmodule
